svg.metadata:
{
  "diagram": "topology-chain-cascade",
  "title": "Line Topology — Cascade",
  "nodes": [
    {"id": "in0",          "role": "input"},
    {"id": "readGate",     "role": "and-gate"},
    {"id": "i0",           "role": "inhibitor",             "index": 0},
    {"id": "i1",           "role": "inhibitor",             "index": 1},
    {"id": "inhibitRight0","role": "inhibit-right-gate"}
  ],
  "edges": [
    {"id": "readGateToI0",     "source": "readGate", "target": "i0",         "kind": "chain"},
    {"id": "i0ToI1",           "source": "i0",       "target": "i1",         "kind": "chain"},
    {"id": "i1AckToReadGate",  "source": "i1",       "target": "readGate",   "kind": "feedback-ack"},
    {"id": "inputToReadGate",  "source": "in0",      "target": "readGate",   "kind": "chain"},
    {"id": "i0ToInhibitRight",         "source": "i0",           "target": "inhibitRight0","kind": "inhibit-in"},
    {"id": "i1ToInhibitRight",         "source": "i1",           "target": "inhibitRight0","kind": "inhibit-in"}
  ],
  "timing": {
    "cycleSeconds": 27,
    "pulseSpeedPxPerSec": 80,
    "steps": [
      {"t": 0.000, "event": "i1 fires → i1AckToReadGate + i1ToInhibitRight depart"},
      {"t": 0.074, "event": "i1ToInhibitRight arrives at inhibitRight0 (waiting for i0)"},
      {"t": 0.331, "event": "i1AckToReadGate arrives at readGate; readGate waits for in0"},
      {"t": 0.739, "event": "in0 fires → inputToReadGate departs"},
      {"t": 0.826, "event": "inputToReadGate arrives; readGate fires (ack already waiting) → readGateToI0"},
      {"t": 0.913, "event": "readGateToI0 arrives; i0 fires → i0ToI1 + i0ToInhibitRight depart"},
      {"t": 0.987, "event": "i0ToInhibitRight arrives; inhibitRight0 fires"},
      {"t": 1.000, "event": "i0ToI1 arrives; i1 fires → t=0 next cycle"}
    ]
  }
}
